UPDATE salons SET reviews='[{"author":"Heena","rating":5,"text":"Kala Shree offers a fantastic range of clothing and accessories that are true to size and in stock. The polite and helpful staff ensure a good fitting, and the management is top-notch. Plus, there are discounts available, making it an excellent choice for all your fashion needs.","date":"Jun 2024"},{"author":"Mansi","rating":4,"text":"Kala shree is a popular name for party wear stuff in Karol Bagh.. they have really great range and variety of all party wear clothing and bridal collections.. you can even buy daaj and vari material from them as well.. once you visits them you will love the designs..Moreover their staff is very nice.. recommended","date":"Feb 2023"},{"author":"Shweta","rating":5,"text":"Wow I really had a gr8 experience with them .... bought my wedding lehenga and dresses was really satisfied, quality things at best prices. Just loved the outfits over there . Its a one stop shop for the bridal wears , a must visit shop.","date":"May 2018"},{"author":"Juhi","rating":3.5,"text":"","date":"Sep 2016"},{"author":"Raju","rating":5,"text":"Excellent","date":"Dec 2014"},{"author":"Kriti","rating":3,"text":"","date":"Oct 2013"}]'::jsonb WHERE id='c2b4cf0f-bfb6-428b-8b6f-40635749c0b5';
UPDATE salons SET reviews='[{"author":"Kanika","rating":3,"text":"","date":"Aug 2022"},{"author":"Sunita","rating":3,"text":"","date":"Feb 2021"},{"author":"Minu","rating":4.5,"text":"Excellent collection of fabulous, latest, trendy lehengas, dresses and sarees. Truly appreciate and admire their good service, friendly staff so abrupt and quick. Will always visit the showroom whenever need to. Best of luck and highly recommend.","date":"Jun 2018"},{"author":"Uruj","rating":4.5,"text":"It is always an amazing experience buying dresses from Sudhir bhai sari wala","date":"Feb 2018"},{"author":"Poonam","rating":5,"text":"Nice Collection","date":"Feb 2018"},{"author":"Puneet","rating":5,"text":"Excellent collection. We are shopping from this shop since past 12 years for all our family weddings.","date":"Apr 2013"}]'::jsonb WHERE id='dc06d2a6-780d-4191-8b6f-2e73d80fc4e1';
