UPDATE salons SET reviews='[{"author":"Lanei","rating":5,"text":"Lots of love for sincerely bridal my pleasure is that I got to wear your gown, you are indeed worthy of your brand ''sincere''. Thank you so much. And if anyone looking for a gown i highly recommend ''go for sincerely bridal'' there''s no regret..","date":"Feb 2020"},{"author":"Yanthan","rating":4.5,"text":"Sincerely Bridal (SB) is the best thing that has happened to Delhi. SB haw been fulfilling the dreams of thousands of couples. SB designs are classy, contemporary and simply beautiful...","date":"May 2019"},{"author":"Sharon","rating":5,"text":"Good service and fully satisfied.","date":"Nov 2017"},{"author":"Samridhi","rating":4,"text":"","date":"Oct 2016"},{"author":"Govindra","rating":5,"text":"Very unique, stylish and you will get your gown more than your expectation.","date":"Aug 2015"},{"author":"Rinki","rating":3,"text":"","date":"May 2014"}]'::jsonb WHERE id='e26007bb-e422-493b-8ff8-614cfc77736c';
